import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { supabase, getMyToken } from '../lib/supabase';

export default function JoinLeague() {
  const { inviteCode } = useParams();
  const navigate = useNavigate();
  const [league, setLeague] = useState(null);
  const [displayName, setDisplayName] = useState('');
  const [loading, setLoading] = useState(true);
  const [joining, setJoining] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    async function load() {
      const { data } = await supabase
        .from('leagues')
        .select('*')
        .eq('invite_code', inviteCode.toLowerCase())
        .single();
      if (!data) setError('League not found. Check your invite link.');
      else {
        // Check if already a member
        const token = getMyToken();
        const { data: member } = await supabase
          .from('members')
          .select('*')
          .eq('league_id', data.id)
          .eq('browser_token', token)
          .single();
        if (member) {
          navigate(`/league/${data.id}`);
          return;
        }
        setLeague(data);
      }
      setLoading(false);
    }
    load();
  }, [inviteCode, navigate]);

  async function handleJoin() {
    if (!displayName.trim()) { setError('Enter a display name.'); return; }
    setJoining(true);
    setError('');
    const token = getMyToken();
    const { error: err } = await supabase.from('members').insert({
      league_id: league.id,
      display_name: displayName.trim(),
      browser_token: token,
      is_composer: false,
    });
    if (err) {
      setError(err.message.includes('unique') ? 'That name is already taken in this league.' : err.message);
      setJoining(false);
      return;
    }
    navigate(`/league/${league.id}`);
  }

  if (loading) return <div className="page"><div className="spinner" /></div>;

  return (
    <div className="page">
      <div className="app-header">
        <div className="logo">F.A.R.T. <span>League</span></div>
      </div>

      {error && !league && <div className="alert alert-error">{error}</div>}

      {league && (
        <>
          <div className="eyebrow">You've been invited</div>
          <h1 style={{ marginBottom: 4 }}>{league.name}</h1>
          <p className="muted" style={{ marginBottom: 32, textTransform: 'capitalize' }}>
            {league.type} league · {league.round_duration_days}-day rounds
          </p>

          {error && <div className="alert alert-error">{error}</div>}

          <div className="card">
            <div className="form-group" style={{ marginBottom: 0 }}>
              <label>Pick Your Display Name</label>
              <input
                placeholder="Something your friends will recognise"
                value={displayName}
                onChange={e => setDisplayName(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleJoin()}
                autoFocus
              />
            </div>
          </div>

          <button
            className="btn btn-primary btn-full"
            onClick={handleJoin}
            disabled={joining}
          >
            {joining ? 'Joining...' : 'Join League →'}
          </button>
        </>
      )}
    </div>
  );
}
